import React, { useEffect, useState } from "react";
import { Link } from "react-router-dom";

// components
import Navbar from "components/Navbars/AuthNavbar.js";
import Footer from "components/Footers/Footer.js";

export default function Landing() {
  // ✅ النصوص باللغات
  const texts = [
    "Hello",
    "Bonjour",
    "Ciao",
    "Hola",
    "こんにちは",
    "你好",
    "안녕하세요",
    "नमस्ते",
    "مرحبا"
  ];

  // ✅ state
  const [index, setIndex] = useState(0);
  const [selectedImage, setSelectedImage] = useState(null);

  // ✅ تغيير النص كل 2 ثواني
  useEffect(() => {
    const interval = setInterval(() => {
      setIndex((prev) => (prev + 1) % texts.length);
    }, 2000);

    return () => clearInterval(interval);
  }, []);

  // ✅ بيانات الصور الثلاث مع المحتوى التفصيلي
  const images = [
    {
      id: 1,
      url: "https://placehold.co/800x600/2c3e50/ffffff?text=QR+Code",
      title: "رمز QR",
      description: "طريقة ذكية لبدء الطلب بدون انتظار النادل",
      fullDescription: "يقوم الزبون بمسح رمز QR الموجود على الطاولة، ليتم فتح قائمة الطعام الرقمية مباشرة على هاتفه. يختار الأطباق المفضلة ويضيفها إلى السلة بكل سهولة، ثم يرسل الطلب مباشرة إلى المطبخ.",
      features: ["مسح سريع خلال ثانية", "قائمة تفاعلية", "إرسال مباشر للمطبخ"]
    },
    {
      id: 2,
      url: "https://placehold.co/800x600/34495e/ffffff?text=Waiter",
      title: "العامل والطلبات",
      description: "إدارة فعالة وسريعة للطلبات",
      fullDescription: "يستقبل العامل الطلبات مباشرة على جهازه اللوحي، مع تفاصيل كل طلب: اسم الطبق، الكمية، الملاحظات الخاصة. يتم تحديد مكان الطاولة بدقة، ويظهر ثمن كل طلب بشكل فوري.",
      features: ["تحديد موقع الطاولة", "عرض الأسعار الفورية", "ملاحظات للطاهي"]
    },
    {
      id: 3,
      url: "https://placehold.co/800x600/16a085/ffffff?text=Invoice",
      title: "الفاتورة الذكية",
      description: "حساب آلي دقيق للمجموع",
      fullDescription: "يقوم النظام تلقائياً بحساب إجمالي الطلبات مع الضريبة، ويظهر تفاصيل كل صنف وسعره. يمكن للزبون دفع الفاتورة إلكترونياً عبر التطبيق، أو طلب الفاتورة الورقية.",
      features: ["حساب المجموع مع الضريبة", "تفاصيل كل صنف", "دفع إلكتروني آمن"]
    }
  ];

  const openModal = (image) => {
    setSelectedImage(image);
    document.body.style.overflow = "hidden";
  };

  const closeModal = () => {
    setSelectedImage(null);
    document.body.style.overflow = "auto";
  };

  return (
    <>
      <Navbar transparent />
      <main>
        <div className="relative pt-16 pb-32 flex content-center items-center justify-center min-h-screen">
          {/* ✅ الصور الثلاث مع تأثيرات CSS المتقدمة */}
          <div className="absolute top-0 w-full h-full">
            <ul className="w-full h-full flex m-0 p-0" style={{ listStyle: "none" }}>
              {images.map((image, idx) => (
                <li
                  key={image.id}
                  className="relative overflow-hidden flex-1 transition-all duration-300 cursor-pointer"
                  style={{
                    transition: "all 0.4s cubic-bezier(0.4, 0, 0.2, 1)",
                    borderRight: idx < images.length - 1 ? "1px solid rgba(255,255,255,0.2)" : "none"
                  }}
                  onClick={() => openModal(image)}
                  onMouseEnter={(e) => {
                    // تأثير تكبير القسم عند المرور
                    const items = e.currentTarget.parentElement.children;
                    for (let item of items) {
                      if (item !== e.currentTarget) {
                        item.style.flex = "0 0 80px";
                      }
                    }
                    e.currentTarget.style.flex = "0 1 45%";
                  }}
                  onMouseLeave={(e) => {
                    const items = e.currentTarget.parentElement.children;
                    for (let item of items) {
                      item.style.flex = "1";
                    }
                  }}
                >
                  <img
                    src={image.url}
                    alt={image.title}
                    className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-full h-full object-cover transition-all duration-300"
                    style={{ transition: "transform 0.5s ease" }}
                  />

                  {/* طبقة التدرج والمحتوى */}
                  <div 
                    className="absolute inset-0 opacity-0 invisible transition-all duration-500"
                    style={{
                      background: "linear-gradient(to top, rgba(0, 0, 0, 0.85) 0%, rgba(0, 0, 0, 0.4) 50%, rgba(0, 0, 0, 0) 100%)",
                      transition: "all 0.4s ease"
                    }}
                  >
                    <div 
                      className="absolute left-1/2 bottom-0 -translate-x-1/2 w-3/4 text-center opacity-0 invisible transition-all duration-500"
                      style={{
                        transform: "translateX(-50%) scale(0.85)",
                        transition: "all 0.5s ease"
                      }}
                    >
                      <h2 className="text-white text-xl font-bold mb-2 whitespace-nowrap">
                        {image.title}
                      </h2>
                      <p className="text-gray-200 text-xs">
                        {image.description}
                      </p>
                      <span className="inline-block mt-2 text-xs bg-white bg-opacity-20 px-3 py-1 rounded-full">
                        اضغط للمزيد
                      </span>
                    </div>
                  </div>

                  <style jsx>{`
                    li:hover {
                      flex: 0 1 45% !important;
                      z-index: 10;
                    }
                    li:hover img {
                      transform: translate(-50%, -50%) scale(1.1);
                    }
                    li:hover .absolute.inset-0 {
                      opacity: 1 !important;
                      visibility: visible !important;
                    }
                    li:hover .absolute.left-1\\/2 {
                      opacity: 1 !important;
                      visibility: visible !important;
                      transform: translateX(-50%) scale(1) !important;
                    }
                  `}</style>
                </li>
              ))}
            </ul>
          </div>

          {/* ✅ النص فوق الصور */}
          <div className="container relative mx-auto z-10">
            <div className="items-center flex flex-wrap">
              <div className="w-full lg:w-6/12 px-4 ml-auto mr-auto text-center">
                <div className="pr-12">
                  <h1
                    key={texts[index]}
                    className="text-white font-semibold text-5xl transition-all duration-500 drop-shadow-lg"
                  >
                    {texts[index]}
                  </h1>
                  <p className="mt-4 text-lg text-blueGray-200 drop-shadow">
                    Welcome to our website
                  </p>
                </div>
              </div>
            </div>
          </div>
        </div>

        {/* باقي محتوى الصفحة */}
      </main>
      <Footer />

      {/* ✅ مودال الصورة المكبرة */}
      {selectedImage && (
        <div
          className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black bg-opacity-90 backdrop-blur-sm transition-all duration-300"
          onClick={closeModal}
        >
          <div
            className="relative max-w-4xl w-full bg-white rounded-2xl overflow-hidden shadow-2xl transform transition-all duration-300 scale-100"
            onClick={(e) => e.stopPropagation()}
          >
            <button
              onClick={closeModal}
              className="absolute top-4 right-4 z-10 bg-black bg-opacity-50 hover:bg-opacity-70 text-white w-10 h-10 rounded-full flex items-center justify-center transition-all duration-300 hover:scale-110"
            >
              ✕
            </button>

            <div className="flex flex-col md:flex-row">
              <div className="md:w-1/2 bg-gray-100">
                <img
                  src={selectedImage.url}
                  alt={selectedImage.title}
                  className="w-full h-64 md:h-full object-cover"
                />
              </div>
              <div className="md:w-1/2 p-6 md:p-8">
                <h2 className="text-2xl md:text-3xl font-bold text-gray-800 mb-4">
                  {selectedImage.title}
                </h2>
                <p className="text-gray-600 leading-relaxed mb-4">
                  {selectedImage.fullDescription}
                </p>
                <div className="space-y-2 mb-6">
                  {selectedImage.features.map((feature, i) => (
                    <div key={i} className="flex items-center gap-2 text-sm text-gray-700">
                      <span className="text-green-500">✓</span>
                      {feature}
                    </div>
                  ))}
                </div>
                <div className="border-t pt-4">
                  <p className="text-sm text-gray-500">
                    ✨ هذه إحدى المهام الرئيسية في التطبيق
                  </p>
                </div>
              </div>
            </div>
          </div>
        </div>
      )}
    </>
  );
}
